export const 鎮宅老樹 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.42) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：目箱桁三帶右圈柱
    線(p => p.M(X(0.6), Z(1.2)).L(X(0.6), Z(3.0)));
    線(p => p.M(X(6.4), Z(1.15)).L(X(6.4), Z(2.95)));
    for (const z of [1.2, 2.1, 3.0])
        線(p => p.M(X(0.6), Z(z)).L(X(6.4), Z(z - 0.05)));
    for (const z of [1.2, 2.1, 3.0, 3.9])
        圈(7.0, z);
    // 人字樹小圈
    圈(3.4, 4.3, 0.24);
    連([3.4, 4.3], [2.6, 5.2]);
    連([3.4, 4.3], [4.2, 5.1]);
    圈(2.6, 5.2, 0.24);
    圈(4.2, 5.1, 0.24);
    // 「子子子」楷列（摹形）
    const 子 = (cx) => {
        線(p => p.M(X(cx - 0.6), Z(5.9)).C(X(cx - 0.2), Z(6.05), X(cx + 0.3), Z(6.0), X(cx + 0.6), Z(5.85)), 0.4);
        出(p => p.M(X(cx + 0.1), Z(5.95)).C(X(cx - 0.05), Z(6.5), X(cx - 0.05), Z(7.0), X(cx + 0.05), Z(7.5))
            .C(X(cx + 0.1), Z(7.8), X(cx - 0.15), Z(7.95), X(cx - 0.45), Z(7.9)), 0.42);
        線(p => p.M(X(cx - 0.75), Z(6.75)).L(X(cx + 0.75), Z(6.7)), 0.4);
    };
    子(1.2);
    子(3.6);
    子(6.1);
    // 日箱三
    const 日 = (x0) => {
        線(p => p.M(X(x0), Z(8.4)).L(X(x0), Z(9.9)).L(X(x0 + 1.5), Z(9.87))
            .L(X(x0 + 1.5), Z(8.37)).L(X(x0 - 0.04), Z(8.4)));
        線(p => p.M(X(x0 + 0.08), Z(9.15)).L(X(x0 + 1.42), Z(9.12)), 0.32);
    };
    日(0.6);
    日(2.8);
    日(5.1);
    // 左目梯（五箱）
    線(p => p.M(X(0.7), Z(10.5)).L(X(0.7), Z(19.2)));
    線(p => p.M(X(3.3), Z(10.45)).L(X(3.3), Z(19.15)));
    for (let i = 0; i <= 5; i++)
        線(p => p.M(X(0.7), Z(10.5 + i * 1.74)).L(X(3.3), Z(10.45 + i * 1.74)));
    // 右柱：己罒王死（摹形從簡）
    線(p => p.M(X(4.4), Z(10.6))
        .C(X(4.0), Z(11.1), X(4.2), Z(11.7), X(4.9), Z(11.75))
        .C(X(5.5), Z(11.8), X(5.7), Z(11.3), X(5.3), Z(11.05)), 0.36);
    線(p => p.M(X(4.2), Z(12.5)).L(X(4.2), Z(13.9)).L(X(6.3), Z(13.85))
        .L(X(6.3), Z(12.45)).L(X(4.15), Z(12.5)));
    線(p => p.M(X(4.9), Z(12.55)).L(X(4.88), Z(13.85)), 0.32);
    線(p => p.M(X(5.6), Z(12.5)).L(X(5.58), Z(13.8)), 0.32);
    線(p => p.M(X(4.2), Z(14.6)).L(X(6.3), Z(14.55)), 0.36);
    線(p => p.M(X(5.2), Z(14.6)).L(X(5.18), Z(16.2)), 0.34);
    線(p => p.M(X(4.2), Z(15.4)).L(X(6.3), Z(15.35)), 0.34);
    線(p => p.M(X(4.2), Z(16.2)).L(X(6.3), Z(16.15)), 0.36);
    // 死曲
    出(p => p.M(X(4.3), Z(17.0)).L(X(6.2), Z(16.95)), 0.36);
    出(p => p.M(X(4.7), Z(17.3)).C(X(4.4), Z(18.0), X(4.5), Z(18.7), X(5.0), Z(19.1)), 0.36);
    出(p => p.M(X(5.5), Z(17.3)).L(X(5.5), Z(18.3))
        .C(X(5.5), Z(18.9), X(5.9), Z(19.15), X(6.5), Z(19.0)), 0.36);
};
